1124→/// Mutate a float value.
1125→fn mutate_float(value: &Value, rng: &mut impl Rng) -> Value {
1126→    let n = match value.as_f64() {
1127→        Some(n) => n,
1128→        None => return generate_float(rng),
1129→    };
1130→    let op: u8 = rng.random_range(0..4);
1131→    match op {
1132→        0 => {
1133→            // Epsilon perturbation
1134→            let factor = 1.0 + rng.random_range(-0.1..0.1_f64);
1135→            json!(n * factor)
1136→        }
1137→        1 => {
1138→            // Sign flip
1139→            json!(-n)
1140→        }
1141→        2 => {
1142→            // Special values — NaN becomes null in JSON, Inf becomes null too
1143→            let specials: &[f64] = &[f64::NAN, f64::INFINITY, f64::NEG_INFINITY, 0.0];
1144→            let idx = rng.random_range(0..specials.len());
1145→            json!(specials[idx])
1146→        }
1147→        _ => {
1148→            // Small delta
1149→            let delta = rng.random_range(-1.0..1.0_f64);
1150→            json!(n + delta)
1151→        }
1152→    }

1402→pub fn crossover_inputs(
1403→    parent_a: &[Value],
1404→    parent_b: &[Value],
1405→    params: &[crate::types::ParamInfo],
1406→    crossover_rate: f64,
1407→    rng: &mut impl Rng,
1408→) -> (Vec<Value>, Vec<Value>) {
1409→    let len = parent_a.len().min(parent_b.len()).min(params.len());
1410→
1411→    // No crossover — clone parents
1412→    if rng.random_range(0.0..1.0_f64) >= crossover_rate {
1413→        return (parent_a.to_vec(), parent_b.to_vec());
1414→    }
1415→
1416→    let mut child1 = Vec::with_capacity(len);
1417→    let mut child2 = Vec::with_capacity(len);
1418→
1419→    for i in 0..len {
1420→        let (c1, c2) = crossover_value(&parent_a[i], &parent_b[i], &params[i].typ, rng);
1421→        child1.push(c1);
1422→        child2.push(c2);
1423→    }
1424→
1425→    (child1, child2)
1426→}
