1428→/// Cross over two values according to their type.
1429→///
1430→/// - **Object**: field-level crossover (each field randomly from A or B).
1431→/// - **Array**: single-point crossover (prefix from one, suffix from the other).
1432→/// - **Other types**: uniform swap (randomly assign A→child1/B→child2 or vice versa).
1433→fn crossover_value(a: &Value, b: &Value, typ: &TypeInfo, rng: &mut impl Rng) -> (Value, Value) {
1434→    match typ {
1435→        TypeInfo::Object { fields } => crossover_object(a, b, fields, rng),
1436→        TypeInfo::Array { .. } => crossover_array(a, b, rng),
1437→        TypeInfo::Str => crossover_string(a, b, rng),
1438→        _ => {
1439→            if rng.random_bool(0.5) {
1440→                (a.clone(), b.clone())
1441→            } else {
1442→                (b.clone(), a.clone())
1443→            }
1444→        }
1445→    }
1446→}
1447→
1448→/// Field-level crossover for objects: each field independently chosen from A or B.
1449→fn crossover_object(
1450→    a: &Value,
1451→    b: &Value,
1452→    fields: &[(String, TypeInfo)],
1453→    rng: &mut impl Rng,
1454→) -> (Value, Value) {
1455→    let obj_a = a.as_object();
1456→    let obj_b = b.as_object();
